module SR_latch (
    input wire Invalid_S,
    input wire R,
    output reg Q,
    output reg Qn
);
    always @ (Invalid_S, R) begin
        if (Invalid_S && ~R) begin
            Q <= 1;
            Qn <= 0;
        end else if (~Invalid_S && R) begin
            Q <= 0;
            Qn <= 1;
        end
        // Invalid state handling
        // Both Invalid_S and R should not be high at the same time
    end
endmodule
